<?php

namespace App\Models;

use Illuminate\Database\Eloquent\Model;
use Illuminate\Database\Eloquent\Relations\BelongsTo;
use Illuminate\Database\Eloquent\Relations\HasMany;
use Illuminate\Database\Eloquent\Relations\MorphMany;
use Illuminate\Database\Eloquent\SoftDeletes;

class Post extends Model
{
    use SoftDeletes;

    protected $fillable = [
        'user_id', 'title', 'description', 'location_name',
        'latitude', 'longitude', 'location_privacy', 'species',
        'bait_used', 'gear_notes', 'weight_kg', 'length_cm',
        'caught_at', 'is_visible',
    ];

    protected function casts(): array
    {
        return [
            'latitude' => 'decimal:7',
            'longitude' => 'decimal:7',
            'weight_kg' => 'decimal:2',
            'length_cm' => 'decimal:2',
            'caught_at' => 'datetime',
            'is_visible' => 'boolean',
        ];
    }

    public function user(): BelongsTo
    {
        return $this->belongsTo(User::class);
    }

    public function images(): HasMany
    {
        return $this->hasMany(PostImage::class)->orderBy('sort_order');
    }

    public function comments(): HasMany
    {
        return $this->hasMany(Comment::class)->whereNull('parent_id')->where('is_visible', true)->latest();
    }

    public function allComments(): HasMany
    {
        return $this->hasMany(Comment::class);
    }

    public function likes(): MorphMany
    {
        return $this->morphMany(Like::class, 'likeable');
    }

    public function reports(): MorphMany
    {
        return $this->morphMany(Report::class, 'reportable');
    }

    public function isLikedBy(?User $user): bool
    {
        if (!$user) return false;
        return $this->likes()->where('user_id', $user->id)->exists();
    }

    public function getDisplayLatitudeAttribute(): ?float
    {
        if (!$this->latitude) return null;
        if ($this->location_privacy === 'approximate') {
            return round($this->latitude, 2);
        }
        return $this->latitude;
    }

    public function getDisplayLongitudeAttribute(): ?float
    {
        if (!$this->longitude) return null;
        if ($this->location_privacy === 'approximate') {
            return round($this->longitude, 2);
        }
        return $this->longitude;
    }

    public function getThumbnailUrlAttribute(): ?string
    {
        $image = $this->images->first();
        if (!$image) return null;
        return $image->thumbnail_url;
    }
}
